1368	zone_type_id zone_manager::get_near_zone_type_for_item( const item &it,
1369	        const tripoint_abs_ms &where, int range, const faction_id &fac ) const
1370	{
1371	    const item_category &cat = it.get_category_of_contents();
1372	
1373	    if( has_near( zone_type_LOOT_CUSTOM, where, range, fac ) ) {
1374	        if( !get_near( zone_type_LOOT_CUSTOM, where, range, &it, fac ).empty() ) {
1375	            return zone_type_LOOT_CUSTOM;
1376	        }
1377	    }
1378	    if( has_near( zone_type_LOOT_ITEM_GROUP, where, range, fac ) ) {
1379	        if( !get_near( zone_type_LOOT_ITEM_GROUP, where, range, &it, fac ).empty() ) {
1380	            return zone_type_LOOT_ITEM_GROUP;
1381	        }
1382	    }
1383	    if( it.has_flag( json_flag_FIREWOOD ) ) {
1384	        if( has_near( zone_type_LOOT_WOOD, where, range, fac ) ) {
1385	            return zone_type_LOOT_WOOD;
1386	        }
1387	    }
1388	    if( it.is_corpse() ) {
1389	        if( has_near( zone_type_LOOT_CORPSE, where, range, fac ) ) {
1390	            return zone_type_LOOT_CORPSE;
1391	        }
