176	void arm_shooter( Character &shooter, const itype_id &gun_type,
177	                  const std::vector<itype_id> &mods,
178	                  const itype_id &ammo_type )
179	{
180	    shooter.remove_weapon();
181	    // XL so arrows can fit.
182	    if( !shooter.is_wearing( itype_debug_backpack ) ) {
183	        shooter.worn.wear_item( shooter, item( itype_debug_backpack ), false, false );
184	    }
185	
186	    const itype_id &gun_id( gun_type );
187	    // Give shooter a loaded gun of the requested type.
188	    item_location gun = shooter.i_add( item( gun_id ) );
189	    itype_id ammo_id = ammo_type;
190	    // if ammo is not supplied we want the default
191	    if( ammo_type.is_null() ) {
192	        if( gun->ammo_default().is_null() ) {
193	            ammo_id = item( gun->magazine_default() ).ammo_default();
194	        } else {
195	            ammo_id = gun->ammo_default();
196	        }
197	    } else {
198	        ammo_id = ammo_type;
199	    }
200	    const ammotype &type_of_ammo = item::find_type( ammo_id )->ammo->type;
201	    if( gun->magazine_integral() ) {
202	        item_location ammo = shooter.i_add( item( ammo_id, calendar::turn,
203	                                            gun->ammo_capacity( type_of_ammo ) ) );
204	        REQUIRE( gun.can_reload_with( ammo, true ) );
205	        REQUIRE( shooter.can_reload( *gun, &*ammo ) );
206	        gun->reload( shooter, ammo, gun->ammo_capacity( type_of_ammo ) );
207	    } else {
208	        const itype_id magazine_id = gun->magazine_default();
209	        item_location magazine = shooter.i_add( item( magazine_id ) );
210	        item_location ammo = shooter.i_add( item( ammo_id, calendar::turn,
211	                                            magazine->ammo_capacity( type_of_ammo ) ) );
212	        REQUIRE( magazine.can_reload_with( ammo,  true ) );
213	        REQUIRE( shooter.can_reload( *magazine, &*ammo ) );
214	        magazine->reload( shooter, ammo, magazine->ammo_capacity( type_of_ammo ) );
215	        gun->reload( shooter, magazine, magazine->ammo_capacity( type_of_ammo ) );
216	    }
217	    for( const itype_id &mod : mods ) {
218	        gun->put_in( item( mod ), pocket_type::MOD );
219	    }
220	    shooter.wield( *gun );
221	}
