276	void give_and_activate_bionic( Character &you, bionic_id const &bioid )
277	{
278	    INFO( "bionic " + bioid.str() + " is valid" );
279	    REQUIRE( bioid.is_valid() );
280	
281	    you.add_bionic( bioid );
282	    INFO( "dummy has gotten " + bioid.str() + " bionic " );
283	    REQUIRE( you.has_bionic( bioid ) );
284	
285	    // get bionic's index - might not be "last added" due to "integrated" ones
286	    int bioindex = -1;
287	    for( size_t i = 0; i < you.my_bionics->size(); i++ ) {
288	        const bionic &bio = ( *you.my_bionics )[ i ];
289	        if( bio.id == bioid ) {
290	            bioindex = i;
291	        }
292	    }
293	    REQUIRE( bioindex != -1 );
294	
295	    bionic &bio = you.bionic_at_index( bioindex );
296	    REQUIRE( bio.id == bioid );
297	
298	    // turn on if possible
299	    if( bio.id->has_flag( json_flag_BIONIC_TOGGLED ) && !bio.powered ) {
300	        const std::vector<material_id> fuel_opts = bio.info().fuel_opts;
301	        if( !fuel_opts.empty() ) {
302	            you.set_value( fuel_opts.front().str(), "2" );
303	        }
304	        you.activate_bionic( bio );
305	        INFO( "bionic " + bio.id.str() + " with index " + std::to_string( bioindex ) + " is active " );
306	        REQUIRE( you.has_active_bionic( bioid ) );
307	        if( !fuel_opts.empty() ) {
308	            you.remove_value( fuel_opts.front().str() );
309	        }
310	    }
311	}
